#!/bin/bash
# build_mac_installer.sh — Full macOS release pipeline: Nuitka compile -> .pkg installer.
# Run from the repo root: bash scripts/build/build_mac_installer.sh
#
# NOTE: The following companion files are referenced but NOT generated by this script.
#       Generate them in a follow-up commit when actually building on a Mac:
#         scripts/build/installer/distribution.xml  — productbuild distribution definition
#         scripts/build/installer/resources/        — background image, welcome/readme/license HTML
#         scripts/build/installer/scripts/          — pre/postinstall shell scripts
#       The postinstall.sh for LaunchAgent registration lives at:
#         scripts/build/installer/postinstall.sh    — chmod +x is run by this script

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"

# ── 1. Read version from spec.json ──────────────────────────────────
if command -v python3 &>/dev/null; then
    VERSION=$(python3 -c "import json; print(json.load(open('$REPO_ROOT/scripts/build/spec.json'))['version'])")
elif command -v jq &>/dev/null; then
    VERSION=$(jq -r '.version' "$REPO_ROOT/scripts/build/spec.json")
else
    echo "[installer] ERROR: neither python3 nor jq found — cannot read version from spec.json"
    exit 1
fi

APP_NAME=$(python3 -c "import json; print(json.load(open('$REPO_ROOT/scripts/build/spec.json'))['name'])" 2>/dev/null || echo "Amplifier")
BUNDLE_ID=$(python3 -c "import json; print(json.load(open('$REPO_ROOT/scripts/build/spec.json'))['mac']['bundle_identifier'])" 2>/dev/null || echo "com.pointcapitalis.amplifier")

echo "[installer] Building $APP_NAME v$VERSION for macOS"

# ── 2. Ensure postinstall.sh is executable ───────────────────────────
POSTINSTALL="$REPO_ROOT/scripts/build/installer/postinstall.sh"
if [ -f "$POSTINSTALL" ]; then
    chmod +x "$POSTINSTALL"
fi

# ── 3. Run Nuitka build ──────────────────────────────────────────────
echo "[installer] Step 1/3 — Nuitka compilation"
python3 "$REPO_ROOT/scripts/build/build_mac.py"

APP_BUNDLE="$REPO_ROOT/dist/mac/$APP_NAME.app"
if [ ! -d "$APP_BUNDLE" ]; then
    echo "[installer] ERROR: .app bundle not found at $APP_BUNDLE"
    exit 1
fi

# ── 4. pkgbuild — produce component package ─────────────────────────
echo "[installer] Step 2/3 — pkgbuild (component package)"
INSTALLERS_DIR="$REPO_ROOT/dist/installers"
mkdir -p "$INSTALLERS_DIR"

COMPONENT_PKG="$INSTALLERS_DIR/Amplifier-component.pkg"
SCRIPTS_DIR="$REPO_ROOT/scripts/build/installer/scripts"

pkgbuild \
    --component "$APP_BUNDLE" \
    --identifier "$BUNDLE_ID" \
    --version "$VERSION" \
    --install-location "/Applications" \
    --scripts "$SCRIPTS_DIR" \
    "$COMPONENT_PKG"

# ── 5. productbuild — produce distributable installer ───────────────
echo "[installer] Step 3/3 — productbuild (distribution package)"
DIST_XML="$REPO_ROOT/scripts/build/installer/distribution.xml"
RESOURCES_DIR="$REPO_ROOT/scripts/build/installer/resources"
FINAL_PKG="$INSTALLERS_DIR/Amplifier-v$VERSION.pkg"

productbuild \
    --distribution "$DIST_XML" \
    --resources "$RESOURCES_DIR" \
    --package-path "$INSTALLERS_DIR" \
    "$FINAL_PKG"

echo "[installer] SUCCESS: $FINAL_PKG"
